<script setup lang="ts">import {reactive,ref} from 'vue';import {ElMessage} from 'element-plus';import {useAuthStore} from '@/stores/auth';const auth=useAuthStore(),form=reactive({oldPassword:'',newPassword:'',confirm:''}),loading=ref(false);async function save(){if(form.newPassword!==form.confirm)return ElMessage.warning('两次密码不一致');loading.value=true;try{await auth.changePassword(form.oldPassword,form.newPassword);ElMessage.success('密码已修改')}finally{loading.value=false}};</script>
<template><div class="page"><div class="page-head"><h2>个人设置</h2></div><el-alert v-if="auth.user?.mustChangePassword" title="当前使用临时密码，修改后才能使用其他功能" type="warning" show-icon :closable="false"/><el-card style="max-width:560px;margin-top:16px"><el-descriptions :column="1" border><el-descriptions-item label="用户名">{{auth.user?.username}}</el-descriptions-item><el-descriptions-item label="姓名">{{auth.user?.displayName}}</el-descriptions-item><el-descriptions-item label="角色">{{auth.user?.role}}</el-descriptions-item></el-descriptions><el-divider>修改密码</el-divider><el-form label-position="top"><el-form-item label="原密码"><el-input v-model="form.oldPassword" type="password" show-password/></el-form-item><el-form-item label="新密码（至少8位）"><el-input v-model="form.newPassword" type="password" show-password/></el-form-item><el-form-item label="确认新密码"><el-input v-model="form.confirm" type="password" show-password/></el-form-item><el-button type="primary" :loading="loading" @click="save">保存</el-button></el-form></el-card></div></template>
